Rules.InvariantScript:
Set(varLoading, true);
Reset(PenInputPas);
Set(
    varOrientacao,
    If(App.Width > App.Height, "Paisagem", "Retrato")
);



Set(varLoading, false)

ControlPropertyState.AutoRuleBindingString:
Set(varLoading, true);

Set(
    varDetalheAtual,
    {
        Tipo:       varServicoSelecionado.Tipo,
        HasServico: !IsBlank(varServicoSelecionado.Servico) && varServicoSelecionado.Tipo = "SERVICO",
        HasTroca:   !IsBlank(varServicoSelecionado.Troca)   && varServicoSelecionado.Tipo = "TROCA",
        HasManut:   !IsBlank(varServicoSelecionado.Manut)   && varServicoSelecionado.Tipo = "MANUTENCAO",
        Servico:    varServicoSelecionado.Servico,
        Troca:      varServicoSelecionado.Troca,
        Manut:      varServicoSelecionado.Manut,
        ManutGeral: varServicoSelecionado.ManutGeral
    }
);

Set(varLoading, false)

Rules.InvariantScript:
If(
    IsBlank(CampoObsTroca.Value),
    Reset(CampoObsTroca);
    Navigate(TelaServiços, ScreenTransition.Fade),

    // ── 1) Variáveis base ─────────────────────────────────────────────
    Set(_guidT, varDetalheAtual.Troca.'GUID Trocas de Carro');
    Set(_tDbObs, LookUp('Trocas de Carro', 'GUID Trocas de Carro' = _guidT));

    If(
        IsBlank(_tDbObs),
        Notify("❌ Troca não encontrada. Atualize a tela.", NotificationType.Error, 4000),

        // ── 2) Variáveis de contexto ──────────────────────────────────
        Set(_obsNova, CampoObsTroca.Value);
        Set(_nomeCompleto, varMotoristaUser.'Nome completo');
        Set(_primeiroUltimo,
            First(Split(_nomeCompleto, " ")).Value
            & " " &
            Last(Split(_nomeCompleto, " ")).Value
        );
        Set(_tag, "Obs " & _primeiroUltimo & ": ");
        Set(_ehMot1Obs, _tDbObs.'Motorista 1'.'Email Microsoft' = varMotoristaUser.'Email Microsoft');

        // ── 3) Monta obs acumulativa em Geral ─────────────────────────
        Set(_registroGeral, LookUp(Geral, 'GUID Reserva de Veículos' = _guidSrv));

        If(
            IsBlank(_registroGeral),
            Notify("❌ Registro na operação não encontrado.", NotificationType.Error, 4000),

            Set(_obsAtual, Coalesce(_registroGeral.'Observação Final', ""));

            // Remove entrada anterior deste motorista e reconstrói
            Set(_partesFiltradas,
                Concat(
                    Filter(
                        ForAll(
                            Split(_obsAtual, " | "),
                            { entrada: ThisRecord.Value }
                        ),
                        Not(IsBlank(entrada))
                        && entrada <> ""
                        && Not(StartsWith(entrada, _tag))
                    ),
                    entrada,
                    " | "
                )
            );

            Set(_obsFinal,
                If(
                    IsBlank(_partesFiltradas) || _partesFiltradas = "",
                    _tag & _obsNova,
                    _partesFiltradas & " | " & _tag & _obsNova
                )
            );

            // ── 4) Patch Geral ────────────────────────────────────────
            Set(_errGeral,
                IsError(
                    Patch(
                        Geral,
                        _registroGeral,
                        { 'Observação Final': _obsFinal }
                    )
                )
            );

            // ── 5) Patch Trocas de Carro ──────────────────────────────
            Set(_errTroca,
                IsError(
                    If(
                        _ehMot1Obs,
                        Patch(
                            'Trocas de Carro',
                            _tDbObs,
                            { 'Observação do Motorista 1': _obsNova }
                        ),
                        Patch(
                            'Trocas de Carro',
                            _tDbObs,
                            { 'Observação do Motorista 2': _obsNova }
                        )
                    )
                )
            );

            // ── 6) Resultado ──────────────────────────────────────────
            If(
                _errGeral || _errTroca,
                Notify(
                    "❌ Falha ao salvar."
                    & If(_errGeral, " [Operação]", "")
                    & If(_errTroca, " [Troca]", "")
                    & " Verifique sua conexão.",
                    NotificationType.Error,
                    5000
                ),

                Notify("✅ Observação salva com sucesso!", NotificationType.Success, 3000);
                Reset(CampoObsTroca);
                Navigate(TelaServiços, ScreenTransition.Fade)
            )
        )
    )
)

ControlPropertyState.AutoRuleBindingString:
If(
    IsBlank(CampoObsFinal.Value),
    Reset(CampoObsFinal);
        Navigate(TelaServiços, ScreenTransition.Fade),

    IfError(
        Patch(
            Geral,
            LookUp(Geral, 'GUID Reserva de Veículos' = _guidSrv),
            { 'Observação Final': CampoObsFinal.Value }
        );
        Notify("✅ Observação salva com sucesso!", NotificationType.Success, 3000);
        Reset(CampoObsFinal);
        Navigate(TelaServiços, ScreenTransition.Fade),

        Notify("❌ Falha ao salvar. Verifique sua conexão.", NotificationType.Error, 5000)
    )
)

If(
    varLoading,
    false,

    Set(varLoading, true);

    // ── 1. Variáveis locais ──────────────────────────────────────────
    Set(_guidSrv, varDetalheAtual.Servico.'GUID Reserva de Veículos');

    // Primeiro item PENDENTE da fila única (ignora HEADERs e já concluídos)
    Set(
        _proxItem,
        First(
            SortByColumns(
                Filter(
                    colAgendaUI,
                    !IsBlank(DtOrdem) &&
                    Tipo <> "HEADER" &&
                    !(Tipo = "SERVICO"    && DadosSERVICO.'Status de Operação'     = 'Status de Operação'.Concluído) &&
                    !(Tipo = "TROCA"      && DadosTROCA.'Status da Troca'          = 'Status da Troca de Carro'.Concluída) &&
                    !(Tipo = "MANUTENCAO" && DadosMANUTENCAO.'Status (cr40f_status)' = 'Status (Manutenções)'.Realizado)
                ),
                "DtOrdem",
                SortOrder.Ascending
            )
        )
    );

    // ── 2. Validação: GUID existe ────────────────────────────────────
    If(
        IsBlank(_guidSrv),
        Notify("Não foi possível identificar o serviço.", NotificationType.Error, 4000);
        Set(varLoading, false),

        // ── 3. Validação: fila não está vazia ────────────────────────
        If(
            IsBlank(_proxItem),
            Notify("Nenhum item pendente encontrado na fila.", NotificationType.Error, 4000);
            Set(varLoading, false),

            // ── 4. Validação: este serviço é o primeiro pendente ─────
            If(
                !(_proxItem.Tipo = "SERVICO" &&
                  _proxItem.DadosSERVICO.'GUID Reserva de Veículos' = _guidSrv),
                Notify(
                    "⚠️ Conclua os itens anteriores da fila antes de prosseguir.",
                    NotificationType.Warning,
                    4000
                );
                Set(varLoading, false),

                // ── 5. Validação: ainda não concluído ─────────────────
                If(
                    varDetalheAtual.Servico.'Status de Operação' = 'Status de Operação'.Concluído,
                    Notify("Este serviço já foi concluído.", NotificationType.Information, 4000);
                    Set(varLoading, false),

                    // ── 6. Busca no banco ─────────────────────────────
                    With(
                        { srvDb: LookUp(Geral, 'GUID Reserva de Veículos' = _guidSrv) },

                        If(
                            IsBlank(srvDb),
                            Notify("Serviço não encontrado. Atualize a página.", NotificationType.Error, 4000);
                            Set(varLoading, false),

                            // ── 7. Patch + atualização local ──────────
                            IfError(
                                With(
                                    {
                                        srvAtualizado: Patch(
                                            Geral,
                                            srvDb,
                                            { 'Status de Operação': 'Status de Operação'.Concluído }
                                        )
                                    },

                                    // Atualiza varDetalheAtual em memória
                                    Set(
                                        varDetalheAtual,
                                        Patch(varDetalheAtual, { Servico: srvAtualizado })
                                    );

                                    // Atualiza colAgenda
                                    With(
                                        {
                                            recAgenda: LookUp(
                                                colAgenda,
                                                Tipo = "SERVICO" &&
                                                !IsBlank(DadosSERVICO) &&
                                                DadosSERVICO.'GUID Reserva de Veículos' = _guidSrv
                                            )
                                        },
                                        If(
                                            !IsBlank(recAgenda),
                                            Patch(colAgenda, recAgenda, { DadosSERVICO: srvAtualizado })
                                        )
                                    );

                                    // Atualiza colAgendaUI
                                    With(
                                        {
                                            recAgendaUI: LookUp(
                                                colAgendaUI,
                                                Tipo = "SERVICO" &&
                                                !IsBlank(DadosSERVICO) &&
                                                DadosSERVICO.'GUID Reserva de Veículos' = _guidSrv
                                            )
                                        },
                                        If(
                                            !IsBlank(recAgendaUI),
                                            Patch(colAgendaUI, recAgendaUI, { DadosSERVICO: srvAtualizado })
                                        )
                                    );

                                    Notify("✅ Serviço concluído com sucesso!", NotificationType.Success, 3000);
                                    Set(varLoading, false);
                                    Navigate(TelaServiços, ScreenTransition.Fade)
                                ),

                                // Erro no Patch
                                Notify(
                                    "❌ Falha ao concluir. Verifique sua conexão e tente novamente.",
                                    NotificationType.Error,
                                    5000
                                );
                                Set(varLoading, false)
                            )
                        )
                    )
                )
            )
        )
    )
)

