Rules.InvariantScript:
// ═══════════════════════════════════════════════════════
//  SALVAR MANUTENÇÃO — Blindado contra erros
//  Ordem: Guards → Patch (banco) → Flow (fotos)
// ═══════════════════════════════════════════════════════

Set(varLoading, true);
Set(_ok, true);
Set(_guidM, Blank());
Set(_proxItem, Blank());
Set(_mDb, Blank());
Set(_mAtualizada, Blank());
Set(_patchGeral, Blank());

// ── GUARD 1: GUID da manutenção ─────────────────────────
If(
    _ok,
    If(
        IsBlank(varDetalheAtual.Manut.'GUID Manutenções'),
        Notify("Erro: não foi possível identificar a manutenção. Volte e tente novamente.", NotificationType.Error, 5000);
        Set(varLoading, false);
        Set(_ok, false),
        Set(_guidM, varDetalheAtual.Manut.'GUID Manutenções')
    )
);

// ── GUARD 2: Já está realizada? ─────────────────────────
If(
    _ok,
    If(
        varDetalheAtual.Manut.'Status (cr40f_status)' = 'Status (Manutenções)'.Realizado,
        Notify("Esta manutenção já foi finalizada anteriormente.", NotificationType.Information, 5000);
        Set(varLoading, false);
        Set(_ok, false)
    )
);

// ── GUARD 3: Campos obrigatórios preenchidos ─────────────
If(
    _ok,
    If(
        IsBlank(CampoFormadePagamentoManutenção.Selected.Value) ||
        IsBlank(CampoEstabelecimentoManutenção.Value) ||
        IsBlank(CampoValorManutenção.Text) ||
        IsBlank(CampoManutençãoRealizada.Value),
        Notify("Preencha corretamente: Manutenção Realizada, Forma de Pagamento, Estabelecimento e Valor.", NotificationType.Warning, 5000);
        Set(varLoading, false);
        Set(_ok, false)
    )
);

// ── GUARD 4: Primeiro item pendente da fila ──────────────
If(
    _ok,
    Set(
    _proxItem,
    First(
        SortByColumns(
            Filter(
                colAgendaUI,
                !IsBlank(DtOrdem) &&
                Tipo <> "HEADER" &&
                !(Tipo = "SERVICO"    && !IsBlank(DadosSERVICO)    && ("conclu" in Lower(Text(DadosSERVICO.'Status de Operação'))    || "cancel" in Lower(Text(DadosSERVICO.'Status de Operação')))) &&
                !(Tipo = "TROCA"      && !IsBlank(DadosTROCA)      && ("conclu" in Lower(Text(DadosTROCA.'Status (cr40f_statusdatroca)'))          || "cancel" in Lower(Text(DadosTROCA.'Status (cr40f_statusdatroca)')))) &&
                !(Tipo = "MANUTENCAO" && !IsBlank(DadosMANUTENCAO) && ("realizado" in Lower(Text(DadosMANUTENCAO.'Status (cr40f_status)')) || "conclu" in Lower(Text(DadosMANUTENCAO.'Status (cr40f_status)')) || "cancel" in Lower(Text(DadosMANUTENCAO.'Status (cr40f_status)'))))
            ),
            "DtOrdem",
            SortOrder.Ascending
        )
    )
);
    If(
        IsBlank(_proxItem),
        Notify("Nenhum item pendente encontrado na fila. Atualize a página.", NotificationType.Error, 5000);
        Set(varLoading, false);
        Set(_ok, false)
    )
);

// ── GUARD 5: Esta manutenção é o primeiro pendente? ──────
If(
    _ok,
    If(
        !(
            _proxItem.Tipo = "MANUTENCAO" &&
            !IsBlank(_proxItem.DadosMANUTENCAO) &&
            _proxItem.DadosMANUTENCAO.'GUID Manutenções' = _guidM
        ),
        Notify("⚠️ Existem itens anteriores na fila ainda pendentes. Conclua-os antes de prosseguir.", NotificationType.Warning, 5000);
        Set(varLoading, false);
        Set(_ok, false)
    )
);

// ── GUARD 6: Registro existe no banco (LookUp) ───────────
If(
    _ok,
    Set(_mDb, LookUp(Manutenções, 'GUID Manutenções' = _guidM));
    If(
        IsBlank(_mDb) || IsBlank(_mDb.'GUID Manutenções'),
        Notify("Manutenção não encontrada no servidor. Atualize a página e tente novamente.", NotificationType.Error, 5000);
        Set(varLoading, false);
        Set(_ok, false)
    )
);

// ── AÇÃO 1: Patch no banco (Dataverse) ───────────────────
If(
    _ok,
    Set(
    _mAtualizada,
    IfError(
        Patch(
            Manutenções,
            _mDb,
            {
                'Status (cr40f_status)':      'Status (Manutenções)'.Realizado,
                'Data da Manutenção':          Now(),
                Realizado_por_nome:            varDetalheAtual.ManutGeral.Motorista,
                'Forma de Pagamento':          CampoFormadePagamentoManutenção.Selected.Value,
                Estabelecimento:               CampoEstabelecimentoManutenção.Value,
                Valor:                         Round(Value(Coalesce(CampoValorManutenção.Text, "0")), 2),
                'Comentários do Colaborador':  CampoObservaçõesdaManutenção.Value,
                'Serviço realizado':           CampoManutençãoRealizada.Value
            }
        ),
        Notify(
            "❌ Patch falhou: " & FirstError.Message & " | Fonte: " & FirstError.Source,
            NotificationType.Error,
            8000
        );
        Set(varLoading, false);
        Set(_ok, false);
        Blank()
    )
);

    If(
        IsBlank(_mAtualizada),
        //Notify("❌ Falha ao salvar no banco. Verifique sua conexão e tente novamente."; NotificationType.Error; 5000);;
        Set(varLoading, false);
        Set(_ok, false),

        Set(_mAtualizada, LookUp(Manutenções, 'GUID Manutenções' = _guidM));

        Set(
            varDetalheAtual,
            {
                ManutGeral: varDetalheAtual.ManutGeral,
                Manut:      _mAtualizada,
                Servico:    varDetalheAtual.Servico,
                Troca:      varDetalheAtual.Troca
            }
        );
        UpdateIf(colAgenda,   Tipo = "MANUTENCAO" && DadosMANUTENCAO.'GUID Manutenções' = _guidM, { DadosMANUTENCAO: _mAtualizada });
        UpdateIf(colAgendaUI, Tipo = "MANUTENCAO" && DadosMANUTENCAO.'GUID Manutenções' = _guidM, { DadosMANUTENCAO: _mAtualizada });

        Set(
            _patchGeral,
            IfError(
                Patch(
                    Geral,
                    varDetalheAtual.ManutGeral,
                    {
                        'Observação Final': CampoObservaçõesdaManutenção.Value,
                        'Data de Finalização': Now()
                    }
                ),
                Blank()
            )
        );

        If(
            IsBlank(_patchGeral),
            Notify("⚠️ Dados de manutenção salvos, mas falha ao atualizar observação. Tente novamente.", NotificationType.Warning, 5000);
            Set(varLoading, false);
            Set(_ok, false)
        )
    )
);

// ── AÇÃO 2: Flow — processar e salvar fotos ───────────────
If(
    _ok,
    Notify("Sincronizando fotos com o sistema... Aguarde.", NotificationType.Information, 3000);

    Set(varJSON_NF, JSON(varFotoNotaFiscalManutenção, JSONFormat.IncludeBinaryData));
    Set(varB64_NF, Mid(varJSON_NF, Find(",", varJSON_NF) + 1, Len(varJSON_NF) - Find(",", varJSON_NF) - 1));

    Set(varJSON_F1, JSON(varFoto1Manutenção, JSONFormat.IncludeBinaryData));
    Set(varB64_F1, Mid(varJSON_F1, Find(",", varJSON_F1) + 1, Len(varJSON_F1) - Find(",", varJSON_F1) - 1));

    Set(varJSON_F2, JSON(varFoto2Manutenção, JSONFormat.IncludeBinaryData));
    Set(varB64_F2, Mid(varJSON_F2, Find(",", varJSON_F2) + 1, Len(varJSON_F2) - Find(",", varJSON_F2) - 1));

    Set(varJSON_F3, JSON(varFoto3Manutenção, JSONFormat.IncludeBinaryData));
    Set(varB64_F3, Mid(varJSON_F3, Find(",", varJSON_F3) + 1, Len(varJSON_F3) - Find(",", varJSON_F3) - 1));

    Set(
        varRespostaFlow,
        IfError(
            'FlowSalvarFotosManutenção|AppMotoristas'.Run(
                varDetalheAtual.ManutGeral.'GUID Reserva de Veículos',
                varB64_NF,
                varB64_F1,
                varB64_F2,
                varB64_F3
            ),
            { status: "Erro", mensagem: "Falha ao disparar fluxo" }
        )
    );

    If(
        varRespostaFlow.status <> "Sucesso",
        Notify("⚠️ Dados salvos, mas houve falha ao enviar as fotos. Tente reenviar as fotos.", NotificationType.Warning, 6000);
        Set(varLoading, false);
        Set(_ok, false),

        Notify("✅ Manutenção e fotos salvas com sucesso!", NotificationType.Success, 4000);
        Set(varLoading, false);
        Navigate(TelaServiços, ScreenTransition.Fade)
    )
);

// ── LIMPEZA FINAL ─────────────────────────────────────────
Set(varB64_NF, Blank());
Set(varB64_F1, Blank());
Set(varB64_F2, Blank());
Set(varB64_F3, Blank());
Set(varJSON_NF, Blank());
Set(varJSON_F1, Blank());
Set(varJSON_F2, Blank());
Set(varJSON_F3, Blank());
Set(_ok, Blank());
Set(_guidM, Blank());
Set(_proxItem, Blank());
Set(_mDb, Blank());
Set(_mAtualizada, Blank());
Set(_patchGeral, Blank())

