                    !IsBlank(DtOrdem) &&
                    Tipo <> "HEADER" &&
                    !(Tipo = "SERVICO"    && !IsBlank(DadosSERVICO)     && DadosSERVICO.'Status de Operação'           = 'Status de Operação'.Concluído) &&
                    !(Tipo = "TROCA"      && !IsBlank(DadosTROCA)       && DadosTROCA.'Status da Troca'              = 'Status da Troca de Carro'.Concluída) &&
                    !(Tipo = "MANUTENCAO" && !IsBlank(DadosMANUTENCAO)  && DadosMANUTENCAO.'Status (cr40f_status)'   = 'Status (Manutenções)'.Realizado)
                ),
                "DtOrdem",
                SortOrder.Ascending
            )
        )
    );

    // ── 2) Validação: GUID existe ────────────────────────────────────
    If(
        IsBlank(_guidM),
        Notify("Não foi possível identificar a manutenção.", NotificationType.Error, 3000);
        Set(varLoading, false),

        // ── 3) Validação: fila não está vazia ────────────────────────
        If(
            IsBlank(_proxItem),
            Notify("Nenhum item pendente encontrado na fila.", NotificationType.Error, 3000);
            Set(varLoading, false),

            // ── 4) Validação: esta manutenção é o primeiro pendente ───
            If(
                !(
                    _proxItem.Tipo = "MANUTENCAO" &&
                    !IsBlank(_proxItem.DadosMANUTENCAO) &&
                    _proxItem.DadosMANUTENCAO.'GUID Manutenções' = _guidM
                ),
                Notify("⚠️ Conclua os itens anteriores da fila antes de prosseguir.", NotificationType.Warning, 3000);
                Set(varLoading, false),

                // ── 5) Validação: ainda não realizado ─────────────────
                If(
                    varDetalheAtual.Manut.'Status (cr40f_status)' = 'Status (Manutenções)'.Realizado,
                    Notify("Esta manutenção já está como realizada.", NotificationType.Information, 3000);
                    Set(varLoading, false),

                    // ── 6) Busca no banco ─────────────────────────────
                    With(
                        { mDb: LookUp(Manutenções, 'GUID Manutenções' = _guidM) },

                        If(
                            IsBlank(mDb) || IsBlank(mDb.'GUID Manutenções'),
                            Notify("Manutenção não encontrada. Atualize a página.", NotificationType.Error, 3000);
                            Set(varLoading, false),

                            // ── 7) Patch + atualização local ──────────
                            IfError(
                                With(
                                    {
                                        mAtualizada: Patch(
                                            Manutenções,
                                            mDb,
                                            { 'Status (cr40f_status)': 'Status (Manutenções)'.Realizado }
                                        )
                                    },

                                    // Atualiza varDetalheAtual em memória
                                    Set(
                                        varDetalheAtual,
                                        Patch(varDetalheAtual, { Manut: mAtualizada })
                                    );

                                    // Atualiza colAgenda (se existir item MANUTENCAO)
                                    With(
                                        {
                                            recAgenda: LookUp(
                                                colAgenda,
                                                Tipo = "MANUTENCAO" &&
                                                !IsBlank(DadosMANUTENCAO) &&
                                                DadosMANUTENCAO.'GUID Manutenções' = _guidM
                                            )
                                        },
                                        If(
                                            !IsBlank(recAgenda),
                                            Patch(colAgenda, recAgenda, { DadosMANUTENCAO: mAtualizada })
                                        )
                                    );

                                    // Atualiza colAgendaUI (se existir item MANUTENCAO)
                                    With(
                                        {
                                            recAgendaUI: LookUp(
                                                colAgendaUI,
                                                Tipo = "MANUTENCAO" &&
                                                !IsBlank(DadosMANUTENCAO) &&
                                                DadosMANUTENCAO.'GUID Manutenções' = _guidM
                                            )
                                        },
                                        If(
                                            !IsBlank(recAgendaUI),
                                            Patch(colAgendaUI, recAgendaUI, { DadosMANUTENCAO: mAtualizada })
                                        )
                                    );

                                    Notify("✅ Manutenção finalizada com sucesso!", NotificationType.Success, 3000);
                                    Set(varLoading, false);
                                    Navigate(TelaServiços, ScreenTransition.Fade)
                                ),

                                Notify("❌ Falha ao finalizar. Verifique sua conexão e tente novamente.", NotificationType.Error, 3000);
                                Set(varLoading, false)
                            )
                        )
                    )
                )
            )
        )
    )
);
